from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/data', methods=['GET'])
def get_data():
    data = {
        "message": "Hello from Flask!",
        "version": "1.0",
        "data": [
            {"id": 1, "name": "Item A"},
            {"id": 2, "name": "Item B"}
        ]
    }
    return jsonify(data)

if __name__ == '__main__':
    app.run(debug=True)
